B.YP=new A.m(B.x,"Teknik kelime bilgisi neden \xf6nemlidir",'Havac\u0131l\u0131k s\u0131navlar\u0131, kesin teknik terimleri anlama ve kullanma becerinizi \xf6l\xe7er. Bir teknisyenin **aileron** yerine "u\xe7a\u011f\u0131 kald\u0131ran \u015fey" demesi hem profesyonellikten uzak hem de tehlikelidir.\n\nBu ders, u\xe7ak sistemine g\xf6re grupland\u0131r\u0131lm\u0131\u015f en s\u0131k s\u0131nanan bile\u015fenleri kapsar.',null,null,null)
