B.XB=new A.m(B.x,"Ko\u015ful c\xfcmleleri neden-sonu\xe7 ili\u015fkisi kurar","Havac\u0131l\u0131k prosed\xfcrleri \xe7o\u011funlukla belirli bir ko\u015ful ger\xe7ekle\u015fti\u011finde ne olaca\u011f\u0131n\u0131 anlat\u0131r. Acil durum kontrol listeleri, operasyon k\u0131lavuzlar\u0131 ve s\u0131nav sorular\u0131 ko\u015ful c\xfcmlelerine yo\u011fun bi\xe7imde dayan\u0131r.\n\nHangi ko\u015ful c\xfcmlesi tipini kullanaca\u011f\u0131n\u0131z, durumun **ger\xe7ek/olas\u0131** m\u0131 yoksa **varsay\u0131msal/imk\xe2ns\u0131z** m\u0131 oldu\u011funa g\xf6re belirlenir.",null,null,null)
