B.a5_=s(["The beginning of the missed approach","The start of the final approach segment","The runway threshold","The IAF position"],t.s)
B.aox=new A.q(-271,B.S,641,"The FAF (Final Approach Fix) marks:",B.a5_,1,B.q,null,null,null)
B.adE=s(["Vectors will definitely be given by ATC","The pilot should anticipate radar vectors but fly published procedure if not given","Vectors are not available on this route","The pilot may request vectors"],t.s)
B.amn=new A.q(-272,B.S,642,'"Expect vectors" on a STAR means:',B.adE,1,B.aV,null,null,null)
B.a5v=s(["Climb to speed 220 knots","Maintain 220 KIAS or less","Set Mach 0.220","Not exceed 220 feet per minute climb"],t.s)
B.ala=new A.q(-273,B.S,643,'If a SID shows "S220" at a waypoint, the crew must:',B.a5v,1,B.aV,null,null,null)
