B.ve=new A.aJ("reading_5","SID/STAR Prosed\xfcrleri","Kalk\u0131\u015f ve var\u0131\u015f prosed\xfcr belgelerini okuma","reading","\ud83d\uddfa\ufe0f",B.a52)
B.a1J=new A.m(B.x,"Kaza raporlar\u0131 karma\u015f\u0131k metinlerdir","Havac\u0131l\u0131k kaza soru\u015fturma raporlar\u0131 (ICAO Ek 13 standartlar\u0131na g\xf6re haz\u0131rlananlar gibi) havac\u0131l\u0131k \u0130ngilizcesi s\u0131navlar\u0131nda s\u0131nanan en karma\u015f\u0131k metinlerdendir.\n\nTeknik terminoloji, edilgen yap\u0131lar, dolayl\u0131 anlat\u0131m ve ko\u015ful \xe7\u0131kar\u0131mlar\u0131n\u0131 tek bir belgede bir araya getirirler.",null,null,null)
B.Wx=new A.m(B.v,"\ud83d\udccb Rapor Yap\u0131s\u0131","Standart bir kaza raporu \u015funlar\u0131 i\xe7erir:\n1. **\xd6zet (Synopsis)** \u2014 kazan\u0131n k\u0131sa \xf6zeti\n2. **Olgusal bilgi** \u2014 u\xe7ak, m\xfcrettebat, hava durumu, havaliman\u0131 verileri\n3. **Analiz** \u2014 ne oldu\u011fu ve neden (neden zinciri)\n4. **Bulgular** \u2014 tespit edilen olgular\n5. **Neden** \u2014 muhtemel neden(ler)\n6. **G\xfcvenlik \xf6nerileri** \u2014 neyin de\u011fi\u015fmesi gerekti\u011fi\n\nS\u0131nav sorular\u0131 genellikle **Olgusal Bilgi** ve **Analiz** b\xf6l\xfcmlerini hedefler.",null,null,null)
B.Zx=new A.m(B.v,"\ud83d\udd0d Kritik Okuma Becerileri","Kaza raporu pasajlar\u0131 i\xe7in:\n\u2022 **S\u0131ralama kelimeleri**: prior to, during, following, subsequently, as a result\n\u2022 **Nedensellik dili**: due to, caused by, attributed to, led to, resulted in\n\u2022 **Bulgu ile \xd6neri** aras\u0131ndaki fark: bulgular olgulard\u0131r; \xf6neriler tavsiyedir\n\u2022 **Contributing factor** \u2260 **Probable cause**: katk\u0131da bulunan fakt\xf6rler durumu a\u011f\u0131rla\u015ft\u0131r\u0131r; muhtemel neden birincil sebeptir",null,null,null)
B.Qf=new A.a2("The accident was attributed to the crew's failure to monitor fuel quantity during the extended hold.","Kaza, ekibin uzun s\xfcren bekleme s\u0131ras\u0131nda yak\u0131t miktar\u0131n\u0131 izlememesine ba\u011fland\u0131.","attributed to")
B.Rq=new A.a2("A contributing factor was the inadequate crew resource management training.","Katk\u0131da bulunan bir fakt\xf6r yetersiz ekip kaynak y\xf6netimi e\u011fitimiydi.","contributing factor")
B.a4G=s([B.Qf,B.Rq],t.l)
