B.ZU=new A.m(B.x,"\u0130leri ATC ileti\u015fimi","Temel ATC ileti\u015fim kal\u0131plar\u0131n\u0131 biliyorsun. Bu derste daha karma\u015f\u0131k senaryolar i\xe7in gerekli c\xfcmle yap\u0131lar\u0131n\u0131 tamamlama becerini geli\u015ftireceksin: holding instructions, conditional clearances, re-routes.",null,null,null)
