B.a_R=new A.m(B.x,"T\xfcrb\xfclans neden \xf6zel ileti\u015fim gerektirir?","T\xfcrb\xfclans, yolcularda ve ekipte yaralanmaya yol a\xe7abilen en yayg\u0131n u\xe7u\u015f g\xfcvenli\u011fi sorunlar\u0131ndan biridir. Net ve sakin bir ileti\u015fim, pani\u011fi \xf6nler ve g\xfcvenli\u011fi art\u0131r\u0131r.",null,null,null)
