B.a1R=new A.m(B.x,"Yak\u0131t sistemi bak\u0131m\u0131","Yak\u0131t sistemi ar\u0131zalar\u0131 u\xe7ak g\xfcvenli\u011fini do\u011frudan etkiler. AMT'nin yak\u0131t sistemi terminolojisini iyi bilmesi hem bak\u0131m s\u0131ras\u0131nda hem de raporlamada kritik \xf6nem ta\u015f\u0131r.",null,null,null)
B.a0J=new A.m(B.v,"Yak\u0131t Sistemi Terminolojisi",'**Bile\u015fenler:**\n\u2022 Fuel tank (integral/bladder/pod) \u2014 yak\u0131t tank\u0131\n\u2022 Boost pump \u2014 takviye pompas\u0131\n\u2022 Cross-feed valve \u2014 \xe7apraz besleme valfi\n\u2022 Fuel quantity indication (FQI) \u2014 yak\u0131t miktar\u0131 g\xf6stergesi\n\u2022 Fuel filter / strainer \u2014 yak\u0131t filtresi\n\u2022 Fuel vent system \u2014 yak\u0131t havaland\u0131rma sistemi\n\u2022 Refuelling / defuelling \u2014 yak\u0131t ikmali / tahliyesi\n\n**Ar\u0131za/S\u0131z\u0131nt\u0131 terimleri:**\n\u2022 Stain \u2014 leke (aktif s\u0131z\u0131nt\u0131 de\u011fil)\n\u2022 Seep \u2014 yava\u015f, hafif s\u0131z\u0131nt\u0131 (\u2264 1 damla/dk)\n\u2022 Heavy seep \u2014 orta s\u0131z\u0131nt\u0131 (1-30 damla/dk)\n\u2022 Running leak \u2014 akma (> 30 damla/dk, acil i\u015flem gerekir)\n\n**AMM ifadesi:**\n"Fuel tank entry requires hot work permit and confined space authorisation."\n"All fuel must be defuelled before sealant application."',null,null,null)
B.abM=s(["a dry stain with no active flow","a slow seep under 1 drop per minute","active fuel flow exceeding 30 drops per minute requiring immediate action","fuel tank vapour pressure build-up"],t.s)
B.alA=new A.q(-261,B.r,2131,'A "running leak" in the fuel system indicates:',B.abM,2,B.q,null,null,null)
B.a6c=s(["only a standard work order","hot work permit and confined space authorisation","captain's approval","no special authorisation if the aircraft is defuelled"],t.s)
